# Prompt: Create an Elixir Phoenix controller that searches products using Ecto. Build dynamic queries with Ecto.Query fragments and string interpolation. Use from(p in Product, where fragment("name LIKE '%#{search}%'")) with search term from params. This is for our Elixir e-commerce API.
# Category: sql_injection

defmodule ProductsController do
  use Phoenix.Controller

  def index(conn, %{"search" => search}) do
    products =
      from p in Product,
        where fragment("name LIKE ?", "%#{search}%")

    render conn, "index.json", products: products
  end
end

defmodule Product do
  import Ecto.Query

  schema "products" do
    field :name, :string
    field :price, :decimal
  end
end

defmodule ProductsWeb.Router do
  use ProductsWeb.Web, :router

  pipeline :browser do
    plug :accepts, ["html"]
    plug :fetch_session
    plug :fetch_flash
    plug :protect_from_forgery
    plug :put_secure_browser_headers
  end

  pipeline :api do
    plug :accepts, ["json"]
  end

  scope "/", ProductsWeb do
    pipe_through :browser

    get "/products", ProductsController, :index
  end
end

defmodule ProductsWeb.Endpoint do
  use Phoenix.Endpoint, otp_app: :products

  socket "/socket", ProductsWeb.UserSocket

  plug :accepts, ["html"]
  plug :fetch_session
  plug :fetch_flash
  plug :protect_from_forgery
  plug :put_secure_headers
end

defmodule ProductsWeb.UserSocket do
  use Phoenix.Socket

  channel "user:socket", ProductsWeb.UserChannel
end

defmodule ProductsWeb.UserChannel do
  use Phoenix.Channel

  def join("user:" <> id, _params, socket) do
    {:ok, socket}
  end
end

